previewCss:
.darma-loader-arc-spinner {
  display: inline-block;
  width: 56px;
  height: 56px;
  border-radius: 50%;
  background: conic-gradient(from 0deg, #6366f1 0 80deg, transparent 82deg 360deg);
  -webkit-mask: radial-gradient(farthest-side, transparent calc(100% - 7px), #000 0);
  mask: radial-gradient(farthest-side, transparent calc(100% - 7px), #000 0);
  animation: darma-loader-arc-spinner-spin 0.8s linear infinite;
}
@keyframes darma-loader-arc-spinner-spin { to { transform: rotate(360deg); } }

